  1→import { useEffect, useRef, useState, type KeyboardEvent } from "react";
  2→import { useMatch, useSearch } from "@tanstack/react-router";
  3→import Markdown from "react-markdown";
  4→import { ChatSuggestionPills } from "../components/chat/ChatSuggestionPills";
  5→import { DiscussEntityCard } from "../components/chat/DiscussEntityCard";
  6→import { EntityLink } from "../components/chat/EntityLink";
  7→import type { DiscussEntitySummary } from "../../shared/contracts";
  8→import { useWorkspaceState } from "../stores/workspace-state";
  9→import { useChatSession } from "../hooks/use-chat-session";
 10→import { useGovernanceFeed } from "../hooks/use-governance-feed";
 11→
 12→export function ChatPage() {
 13→  const onboardingState = useWorkspaceState((s) => s.onboardingState);
 14→  const setSidebarHandlers = useWorkspaceState((s) => s.setSidebarHandlers);
 15→
 16→  // Read conversationId from /chat/$conversationId route (undefined on /chat)
 17→  const matchWithId = useMatch({ from: "/chat/$conversationId", shouldThrow: false });
 18→  const routeConversationId = matchWithId?.params.conversationId;
 19→
 20→  // Read message search param (works on both /chat and /chat/:id)
 21→  const search = useSearch({ strict: false });
 22→  const messageParam = (search as { message?: string })?.message;
 23→
 24→  const chat = useChatSession(routeConversationId);
 25→  const { feed } = useGovernanceFeed();
 26→
 27→  // Keep a ref to the latest chat handlers so the effect below doesn't
 28→  // depend on unstable function references.
 29→  const chatRef = useRef(chat);
 30→  chatRef.current = chat;
 31→
 32→  // Register sidebar handlers so the shell sidebar can interact with chat
 33→  useEffect(() => {
 34→    setSidebarHandlers({
 35→      activeConversationId: chat.activeConversationId,
 36→      isLoading: chat.isLoading,
 37→      onNewConversation: () => chatRef.current.newConversation(),
 38→      onSelectConversation: (id: string) => chatRef.current.selectConversation(id),
 39→    });
 40→  }, [chat.activeConversationId, chat.isLoading]);
 41→
 42→  // Cleanup sidebar handlers on unmount
 43→  useEffect(() => {
 44→    return () => {
 45→      setSidebarHandlers(undefined);
 46→    };
 47→  }, []);
 48→
 49→  // Load conversation from URL param on mount/param change
 50→  useEffect(() => {
 51→    if (routeConversationId && routeConversationId !== chat.activeConversationId) {
 52→      chat.selectConversation(routeConversationId);
 53→    }
 54→  }, [routeConversationId]);
 55→
 56→  // Scroll to message from ?message= search param
 57→  useEffect(() => {
 58→    if (!messageParam) return;
 59→
 60→    const timer = setTimeout(() => {
 61→      const element = document.querySelector(`[data-message-id="${CSS.escape(messageParam)}"]`);
 62→      if (element) {
