  1→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
  2→import { useNavigate } from "@tanstack/react-router";
  3→import { useChat, type UseChatHelpers } from "@ai-sdk/react";
  4→import { DefaultChatTransport, type UIMessage } from "ai";
  5→import type {
  6→  BranchConversationResponse,
  7→  DiscussEntitySummary,
  8→  OnboardingAction,
  9→  OnboardingState,
 10→  WorkspaceBootstrapMessage,
 11→  WorkspaceConversationResponse,
 12→} from "../../shared/contracts";
 13→import { useWorkspaceState, type BootstrapPayload } from "../stores/workspace-state";
 14→import { useViewState } from "../stores/view-state";
 15→
 16→type ChatMessageMetadata = {
 17→  onboardingState?: OnboardingState;
 18→  conversationId?: string;
 19→};
 20→
 21→type ChatUIMessage = UIMessage<ChatMessageMetadata>;
 22→
 23→export type UseChatSessionReturn = {
 24→  messages: ChatUIMessage[];
 25→  status: UseChatHelpers<ChatUIMessage>["status"];
 26→  isLoading: boolean;
 27→  errorMessage?: string;
 28→  activeConversationId?: string;
 29→  branchingFromId?: string;
 30→  discussEntity?: DiscussEntitySummary;
 31→  conversationDiscussEntity?: DiscussEntitySummary;
 32→  sendMessage: (text: string, options?: { onboardingAction?: OnboardingAction }) => void;
 33→  stopMessage: () => void;
 34→  newConversation: () => void;
 35→  selectConversation: (conversationId: string) => void;
 36→  branchFromMessage: (messageId: string) => Promise<void>;
 37→  setErrorMessage: (message: string | undefined) => void;
 38→  refreshSidebar: (workspaceId: string) => Promise<void>;
 39→};
 40→
 41→function bootstrapMessagesToUIMessages(messages: WorkspaceBootstrapMessage[]): ChatUIMessage[] {
 42→  return messages.map((m) => ({
 43→    id: m.id,
 44→    role: m.role,
 45→    parts: [{ type: "text" as const, text: m.text }],
 46→    createdAt: new Date(m.createdAt),
 47→  }));
 48→}
 49→
 50→export function useChatSession(routeConversationId?: string): UseChatSessionReturn {
 51→  const store = useWorkspaceState();
 52→  const workspaceId = store.workspaceId;
 53→  const bootstrapPayload = store.bootstrapPayload;
 54→  const navigate = useNavigate();
 55→
 56→  const [activeConversationId, setActiveConversationId] = useState<string | undefined>();
 57→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 58→  const [branchingFromId, setBranchingFromId] = useState<string | undefined>();
 59→  const [conversationDiscussEntity, setConversationDiscussEntity] = useState<
 60→    DiscussEntitySummary | undefined
 61→  >();
 62→
 63→  const discussEntity = useViewState((s) => s.discussEntity);
 64→  const clearDiscussEntity = useViewState((s) => s.clearDiscussEntity);
 65→
 66→  // Dynamic body refs — these are read by the transport body function
 67→  const conversationIdRef = useRef<string | undefined>(undefined);
 68→  const onboardingActionRef = useRef<OnboardingAction | undefined>(undefined);
 69→  const discussEntityIdRef = useRef<string | undefined>(undefined);
 70→
 71→  // Keep conversationId ref in sync
 72→  useEffect(() => {
 73→    conversationIdRef.current = activeConversationId;
 74→  }, [activeConversationId]);
 75→
 76→  // Keep discuss entity ref in sync
 77→  useEffect(() => {
 78→    discussEntityIdRef.current = discussEntity?.id;
 79→  }, [discussEntity]);
 80→
 81→  const transport = useMemo(
 82→    () =>
 83→      new DefaultChatTransport({
 84→        api: "/api/chat",
 85→        body: () => ({
 86→          workspaceId,
 87→          ...(conversationIdRef.current ? { conversationId: conversationIdRef.current } : {}),
 88→          ...(onboardingActionRef.current
 89→            ? { onboardingAction: onboardingActionRef.current }
 90→            : {}),
 91→          ...(discussEntityIdRef.current
 92→            ? { discussEntityId: discussEntityIdRef.current }
 93→            : {}),
 94→        }),
 95→      }),
 96→    [workspaceId],
 97→  );
 98→
 99→  const chat = useChat<ChatUIMessage>({
100→    transport,
101→    onFinish: ({ message }) => {
102→      const metadata = message.metadata;
103→      if (metadata?.conversationId && !conversationIdRef.current) {
104→        setActiveConversationId(metadata.conversationId);
105→        conversationIdRef.current = metadata.conversationId;
106→        void navigate({
107→          to: "/chat/$conversationId",
108→          params: { conversationId: metadata.conversationId },
109→          replace: true,
110→        });
111→        if (discussEntity) {
112→          clearDiscussEntity();
113→        }
114→      }
115→      if (metadata?.onboardingState) {
116→        store.setOnboardingState(metadata.onboardingState);
117→      }
118→
119→      // Refresh sidebar
120→      if (workspaceId) {
121→        void refreshSidebar(workspaceId);
122→      }
123→    },
124→    onError: (error) => {
125→      setErrorMessage(error.message);
126→    },
127→  });
128→
129→  const isLoading = chat.status === "streaming" || chat.status === "submitted";
130→
131→  // Apply bootstrap payload when it arrives — only load messages when on /chat/:id
132→  const appliedBootstrapRef = useRef<BootstrapPayload | undefined>(undefined);
133→  useEffect(() => {
134→    if (!bootstrapPayload || bootstrapPayload === appliedBootstrapRef.current) {
135→      return;
136→    }
137→    appliedBootstrapRef.current = bootstrapPayload;
138→
139→    // On /chat (new conversation), skip loading bootstrap messages
140→    if (!routeConversationId) {
141→      return;
142→    }
143→
144→    chat.setMessages(bootstrapPayload.messages as ChatUIMessage[]);
145→    setActiveConversationId(store.conversationId);
146→    conversationIdRef.current = store.conversationId;
147→  }, [bootstrapPayload, routeConversationId]);
148→
149→  async function refreshSidebar(wsId: string) {
150→    try {
151→      const response = await fetch(`/api/workspaces/${encodeURIComponent(wsId)}/sidebar`);
152→      if (response.ok) {
153→        const payload = await response.json();
154→        store.setSidebar(payload);
155→      }
156→    } catch {
157→      // Sidebar refresh is non-critical
158→    }
159→  }
160→
161→  async function loadConversation(wsId: string, conversationId: string) {
162→    try {
163→      const response = await fetch(
164→        `/api/workspaces/${encodeURIComponent(wsId)}/conversations/${encodeURIComponent(conversationId)}`,
165→      );
166→      if (!response.ok) {
167→        const body = await response.text();
168→        setErrorMessage(body);
169→        void navigate({ to: "/chat", replace: true });
170→        return;
171→      }
172→
173→      const payload = (await response.json()) as WorkspaceConversationResponse;
174→      const uiMessages = bootstrapMessagesToUIMessages(payload.messages) as ChatUIMessage[];
175→      chat.setMessages(uiMessages);
176→
177→      setActiveConversationId(conversationId);
178→      conversationIdRef.current = conversationId;
179→      setConversationDiscussEntity(payload.discussEntity);
180→    } catch (error) {
181→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
182→      setErrorMessage(messageText);
183→    }
184→  }
185→
186→  const sendMessage = useCallback(
187→    (text: string, options?: { onboardingAction?: OnboardingAction }) => {
188→      if (isLoading || !workspaceId) return;
189→
190→      const trimmed = text.trim();
191→      if (!trimmed) return;
192→
193→      setErrorMessage(undefined);
194→      onboardingActionRef.current = options?.onboardingAction;
195→
196→      chat.sendMessage({ text: trimmed });
197→
198→      // Clear after queueing
199→      onboardingActionRef.current = undefined;
200→    },
201→    [isLoading, workspaceId, chat.sendMessage],
202→  );
203→
204→  function stopMessage() {
205→    chat.stop();
206→  }
207→
208→  function newConversation() {
209→    setActiveConversationId(undefined);
210→    conversationIdRef.current = undefined;
211→    chat.setMessages([]);
212→    setErrorMessage(undefined);
213→    setConversationDiscussEntity(undefined);
214→    clearDiscussEntity();
215→    void navigate({ to: "/chat" });
216→  }
217→
218→  function selectConversation(conversationId: string) {
219→    if (conversationId === activeConversationId || isLoading || !workspaceId) {
220→      return;
221→    }
222→    void loadConversation(workspaceId, conversationId);
223→  }
224→
225→  async function branchFromMessage(messageId: string) {
226→    if (!workspaceId || !activeConversationId || isLoading) return;
227→
228→    setBranchingFromId(messageId);
229→    try {
230→      const response = await fetch(
231→        `/api/workspaces/${encodeURIComponent(workspaceId)}/conversations/${encodeURIComponent(activeConversationId)}/branch`,
232→        {
233→          method: "POST",
234→          headers: { "Content-Type": "application/json" },
235→          body: JSON.stringify({ messageId }),
236→        },
237→      );
238→
239→      if (!response.ok) {
240→        const body = await response.text();
241→        setErrorMessage(body);
242→        return;
243→      }
244→
245→      const payload = (await response.json()) as BranchConversationResponse;
246→      await loadConversation(workspaceId, payload.conversationId);
247→      void navigate({
248→        to: "/chat/$conversationId",
249→        params: { conversationId: payload.conversationId },
250→      });
251→      await refreshSidebar(workspaceId);
252→    } catch (error) {
253→      const messageText = error instanceof Error ? error.message : "Branch creation failed";
254→      setErrorMessage(messageText);
255→    } finally {
256→      setBranchingFromId(undefined);
257→    }
258→  }
259→
260→  return {
261→    messages: chat.messages,
262→    status: chat.status,
263→    isLoading,
264→    errorMessage,
265→    activeConversationId,
266→    branchingFromId,
267→    discussEntity,
268→    conversationDiscussEntity,
269→    sendMessage,
270→    stopMessage,
271→    newConversation,
272→    selectConversation,
273→    branchFromMessage,
274→    setErrorMessage,
275→    refreshSidebar,
276→  };
277→}
