 12→
 13→const CONFIRMABLE_STATUSES = new Set(["extracted", "proposed", "provisional", "inferred"]);
 14→
 15→export function EntityDetailPanel({
 16→  entityId,
 17→  workspaceId,
 18→  onClose,
 19→  onEntityClick,
 20→}: {
 21→  entityId: string;
 22→  workspaceId: string;
 23→  onClose: () => void;
 24→  onEntityClick: (entityId: string) => void;
 25→}) {
 26→  const [detail, setDetail] = useState<EntityDetailResponse | undefined>();
 27→  const [loading, setLoading] = useState(true);
 28→  const [error, setError] = useState<string | undefined>();
 29→  const [actionPending, setActionPending] = useState(false);
 30→  const navigateToDiscussEntity = useViewState((s) => s.navigateToDiscussEntity);
 31→  const navigate = useNavigate();
 32→
 33→  useEffect(() => {
 34→    setLoading(true);
 35→    setError(undefined);
 36→
 37→    fetch(`/api/entities/${encodeURIComponent(entityId)}?workspaceId=${encodeURIComponent(workspaceId)}`)
 38→      .then(async (response) => {
 39→        if (!response.ok) {
 40→          const body = await response.text();
 41→          throw new Error(body);
 42→        }
 43→        return response.json() as Promise<EntityDetailResponse>;
 44→      })
 45→      .then((data) => {
 46→        setDetail(data);
 47→        setLoading(false);
 48→      })
 49→      .catch((err) => {
 50→        setError(err instanceof Error ? err.message : "Failed to load entity");
 51→        setLoading(false);
 52→      });
 53→  }, [entityId, workspaceId]);
 54→
 55→  function handleJumpToMessage(messageId: string, conversationId?: string) {
 56→    if (conversationId) {
 57→      void navigate({ to: "/chat/$conversationId", params: { conversationId }, search: { message: messageId } });
 58→    } else {
 59→      void navigate({ to: "/chat", search: { message: messageId } });
 60→    }
 61→  }
 62→
 63→  async function handleConfirm() {
 64→    if (!detail || actionPending) return;
 65→    setActionPending(true);
 66→    try {
 67→      await confirmDecision(workspaceId, entityId);
 68→      setDetail((prev) =>
 69→        prev
 70→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "confirmed" } } }
 71→          : prev,
 72→      );
 73→    } finally {
 74→      setActionPending(false);
 75→    }
 76→  }
 77→
 78→  async function handleOverride() {
 79→    if (!detail || actionPending) return;
 80→    const newSummary = window.prompt("New decision summary:");
 81→    if (!newSummary) return;
 82→    setActionPending(true);
 83→    try {
 84→      await overrideDecision(workspaceId, entityId, newSummary);
 85→      setDetail((prev) =>
 86→        prev
 87→          ? {
 88→              ...prev,
 89→              entity: {
 90→                ...prev.entity,
 91→                name: newSummary,
 92→                data: { ...prev.entity.data, status: "overridden", summary: newSummary },
 93→              },
 94→            }
 95→          : prev,
 96→      );
 97→    } finally {
 98→      setActionPending(false);
 99→    }
100→  }
101→
102→  async function handleComplete() {
103→    if (!detail || actionPending) return;
104→    setActionPending(true);
105→    try {
106→      await markTaskComplete(workspaceId, entityId);
107→      setDetail((prev) =>
108→        prev
109→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "done" } } }
110→          : prev,
111→      );
112→    } finally {
113→      setActionPending(false);
114→    }
115→  }
116→
117→  if (loading) {
118→    return (
119→      <aside className="entity-detail-panel">
120→        <p className="entity-detail-meta">Loading...</p>
121→      </aside>
122→    );
123→  }
124→
125→  if (error || !detail) {
