131→        </div>
132→      </aside>
133→    );
134→  }
135→
136→  const kind = detail.entity.kind as EntityKind;
137→  const status = (detail.entity.data.status as string | undefined) ?? "";
138→  const rationale = detail.entity.data.rationale as string | undefined;
139→
140→  const showConfirm = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
141→  const showOverride = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
142→  const showComplete = kind === "task" && status !== "done";
143→
144→  return (
145→    <aside className="entity-detail-panel">
146→      <div className="entity-detail-header">
147→        <div>
148→          <EntityBadge kind={kind} />
149→          <h3>{detail.entity.name}</h3>
150→        </div>
151→        <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
152→      </div>
153→
154→      <div className="entity-detail-section">
155→        <h4>Metadata</h4>
156→        <dl className="entity-detail-meta">
157→          {status ? (
158→            <>
159→              <dt>Status</dt>
160→              <dd>{status}</dd>
161→            </>
162→          ) : undefined}
163→          {typeof detail.entity.data.category === "string" && (ENTITY_CATEGORIES as readonly string[]).includes(detail.entity.data.category) ? (
164→            <>
165→              <dt>Category</dt>
166→              <dd><CategoryBadge category={detail.entity.data.category as EntityCategory} /></dd>
167→            </>
168→          ) : undefined}
169→          {detail.entity.data.confidence !== undefined ? (
170→            <>
171→              <dt>Confidence</dt>
172→              <dd>{(detail.entity.data.confidence as number).toFixed(2)}</dd>
173→            </>
174→          ) : undefined}
175→          {detail.entity.data.created_at ? (
176→            <>
177→              <dt>Created</dt>
178→              <dd>{new Date(detail.entity.data.created_at as string).toLocaleDateString()}</dd>
179→            </>
180→          ) : undefined}
181→          {detail.entity.data.owner_name ? (
182→            <>
183→              <dt>Owner</dt>
184→              <dd>{detail.entity.data.owner_name as string}</dd>
185→            </>
186→          ) : undefined}
187→          {(kind === "task" || kind === "decision" || kind === "question") ? (
188→            <>
189→              <dt>Priority</dt>
190→              <dd>
191→                <select
192→                  value={(detail.entity.data.priority as string | undefined) ?? ""}
193→                  disabled={actionPending}
194→                  onChange={async (e) => {
