201→                        prev
202→                          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, priority: value } } }
203→                          : prev,
204→                      );
205→                    } finally {
206→                      setActionPending(false);
207→                    }
208→                  }}
209→                >
210→                  <option value="" disabled>—</option>
211→                  {ENTITY_PRIORITIES.map((p) => (
212→                    <option key={p} value={p}>{p}</option>
213→                  ))}
214→                </select>
215→              </dd>
216→            </>
217→          ) : undefined}
218→        </dl>
219→      </div>
220→
221→      <DescriptionSection data={detail.entity.data} kind={kind} onEntityClick={onEntityClick} />
222→
223→      {rationale ? (
