229→
230→      <RelationshipList relationships={detail.relationships} onEntityClick={onEntityClick} />
231→
232→      <ProvenanceSection provenance={detail.provenance} onJumpToMessage={handleJumpToMessage} />
233→
234→      <div className="entity-detail-actions">
