 25→async function handlePostChatMessage(deps: ServerDependencies, request: Request): Promise<Response> {
 26→  const startedAt = performance.now();
 27→  logInfo("chat.message.ingress.started", "Chat message ingress started");
 28→
 29→  let parsed: Awaited<ReturnType<typeof parseIncomingMessageRequest>>;
 30→  try {
 31→    parsed = await parseIncomingMessageRequest(request);
 32→  } catch (error) {
 33→    logError("chat.message.parse.failed", "Parsing incoming chat message failed", error);
 34→    const errorText = error instanceof Error ? error.message : "invalid request body";
 35→    return jsonError(errorText, 400);
 36→  }
 37→
 38→  if (!parsed.ok) {
 39→    return jsonError(parsed.error, 400);
 40→  }
 41→
 42→  const conversationId = parsed.data.conversationId ?? randomUUID();
 43→  const messageId = randomUUID();
 44→  const workspaceId = parsed.data.workspaceId;
 45→  const userText = parsed.data.text.trim();
 46→  const onboardingAction = parsed.data.onboardingAction;
 47→  const messageText = userText.length > 0 ? userText : `Uploaded document: ${parsed.data.attachment?.fileName ?? "attachment"}`;
 48→  const userMessageRecord = new RecordId("message", randomUUID());
 49→
 50→  logDebug("http.request.validated", "Chat message request validated", {
 51→    workspaceId,
 52→    conversationId,
 53→    hasAttachment: parsed.data.attachment !== undefined,
 54→  });
 55→
 56→  let workspaceRecord: RecordId<"workspace", string>;
 57→
 58→  try {
 59→    logInfo("chat.message.persist.started", "Persisting user chat message", {
 60→      workspaceId,
 61→      conversationId,
 62→      messageId,
 63→    });
 64→
 65→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 66→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
 67→    if (!workspace) {
 68→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
 69→    }
 70→
 71→    const discussEntityTables = ["project", "person", "feature", "task", "decision", "question", "observation"] as const;
 72→    const discussesRecord = parsed.data.discussEntityId
 73→      ? parseRecordIdString(parsed.data.discussEntityId, [...discussEntityTables])
 74→      : undefined;
 75→
 76→    const now = new Date();
 77→    const conversationRecord = new RecordId("conversation", conversationId);
 78→    const existingConversation = await deps.surreal.select<ConversationRow>(conversationRecord);
 79→
 80→    const transaction = await deps.surreal.beginTransaction();
 81→    try {
 82→      if (existingConversation) {
 83→        if (!existingConversation.workspace) {
 84→          throw new HttpError(500, "conversation is missing workspace scope");
 85→        }
 86→
 87→        if (existingConversation.workspace.id !== workspaceRecord.id) {
 88→          throw new HttpError(400, "conversation scope does not match workspaceId");
 89→        }
 90→
 91→        await transaction.update(conversationRecord).merge({
 92→          updatedAt: now,
 93→        });
 94→      } else {
 95→        await transaction.create(conversationRecord).content({
 96→          createdAt: now,
 97→          updatedAt: now,
 98→          workspace: workspaceRecord,
 99→          title: deriveMessageTitle(messageText),
100→          title_source: "message",
101→          ...(workspace.onboarding_complete ? {} : { source: "onboarding" }),
102→          ...(discussesRecord ? { discusses: discussesRecord } : {}),
103→        });
104→      }
105→
106→      await transaction.create(userMessageRecord).content({
107→        conversation: conversationRecord,
108→        role: "user",
109→        text: messageText,
110→        createdAt: now,
111→        clientMessageId: parsed.data.clientMessageId,
112→      });
113→
114→      if (!workspace.onboarding_complete) {
115→        await transaction.update(workspaceRecord).merge({
116→          onboarding_turn_count: workspace.onboarding_turn_count + 1,
117→          updated_at: now,
118→        });
119→      }
120→
121→      await transaction.commit();
122→    } catch (error) {
123→      await transaction.cancel();
124→      throw error;
125→    }
126→
127→    logInfo("chat.message.persist.completed", "User chat message persisted", {
128→      workspaceId,
129→      conversationId,
130→      messageId,
131→      userMessageId: userMessageRecord.id as string,
132→    });
133→  } catch (error) {
134→    if (error instanceof HttpError) {
135→      logWarn("chat.message.persist.http_error", "Chat message persistence failed with client-facing error", {
136→        workspaceId,
137→        conversationId,
138→        messageId,
139→        statusCode: error.status,
140→      });
141→      return jsonError(error.message, error.status);
142→    }
143→
144→    logError("chat.message.persist.failed", "Persisting user chat message failed", error, {
145→      workspaceId,
146→      conversationId,
147→      messageId,
148→    });
149→    const errorText = error instanceof Error ? error.message : "failed to persist user message";
150→    return jsonError(errorText, 500);
151→  }
152→
153→  deps.sse.registerMessage(messageId);
154→
155→  logInfo("chat.message.process.started", "Async chat processing started", {
156→    workspaceId,
157→    conversationId,
158→    messageId,
159→  });
160→
161→  void processChatMessage({
162→    deps,
163→    conversationId,
164→    messageId,
165→    workspaceRecord,
166→    userMessageRecord,
167→    userText: messageText,
168→    attachment: parsed.data.attachment,
169→    ...(onboardingAction ? { onboardingAction } : {}),
170→  });
171→
172→  const response: ChatMessageResponse = {
173→    messageId,
174→    userMessageId: userMessageRecord.id as string,
175→    conversationId,
176→    workspaceId,
177→    streamUrl: `/api/chat/stream/${messageId}`,
178→  };
179→
180→  logInfo("chat.message.ingress.completed", "Chat message ingress completed", {
181→    workspaceId,
182→    conversationId,
183→    messageId,
184→    durationMs: elapsedMs(startedAt),
185→  });
186→
187→  return jsonResponse(response, 200);
188→}
