390→async function handleWorkspaceConversation(
391→  deps: ServerDependencies,
392→  workspaceId: string,
393→  conversationId: string,
394→): Promise<Response> {
395→  const startedAt = performance.now();
396→  logInfo("workspace.conversation.started", "Workspace conversation request started", {
397→    workspaceId,
398→    conversationId,
399→  });
400→
401→  try {
402→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
403→    const conversationRecord = new RecordId("conversation", conversationId);
404→    const conversation = await deps.surreal.select<{
405→      id: RecordId<"conversation", string>;
406→      workspace: RecordId<"workspace", string>;
407→      discusses?: RecordId;
408→    }>(conversationRecord);
409→
410→    if (!conversation) {
411→      throw new HttpError(404, `conversation not found: ${conversationId}`);
412→    }
413→
414→    if ((conversation.workspace.id as string) !== (workspaceRecord.id as string)) {
415→      throw new HttpError(400, "conversation does not belong to workspace");
416→    }
417→
418→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
419→
420→    const messages = rawMessages.map((row) => ({
421→      id: row.id,
422→      role: row.role,
423→      text: row.text,
424→      createdAt: toIsoString(row.createdAt),
425→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
426→      ...(row.inherited ? { inherited: true } : {}),
427→    } satisfies WorkspaceBootstrapMessage));
428→
429→    let discussEntity: DiscussEntitySummary | undefined;
430→    if (conversation.discusses) {
431→      const entityRecord = conversation.discusses as GraphEntityRecord;
432→      const name = await readEntityName(deps.surreal, entityRecord);
433→      if (name) {
434→        const entityRow = await deps.surreal.select<Record<string, unknown>>(entityRecord);
435→        discussEntity = {
436→          id: `${entityRecord.table.name}:${entityRecord.id as string}`,
437→          kind: entityRecord.table.name as EntityKind,
438→          name,
439→          ...(entityRow && typeof entityRow.status === "string" ? { status: entityRow.status } : {}),
440→        };
441→      }
442→    }
443→
444→    const payload: WorkspaceConversationResponse = {
445→      conversationId,
446→      messages,
447→      ...(discussEntity ? { discussEntity } : {}),
448→    };
449→
450→    logInfo("workspace.conversation.completed", "Workspace conversation request completed", {
451→      workspaceId,
452→      conversationId,
453→      messageCount: messages.length,
454→      durationMs: elapsedMs(startedAt),
455→    });
456→
457→    return jsonResponse(payload, 200);
458→  } catch (error) {
459→    if (error instanceof HttpError) {
460→      logWarn("workspace.conversation.http_error", "Workspace conversation failed with client-facing error", {
461→        workspaceId,
462→        conversationId,
463→        statusCode: error.status,
464→      });
465→      return jsonError(error.message, error.status);
466→    }
467→
468→    logError("workspace.conversation.failed", "Workspace conversation request failed", error, {
469→      workspaceId,
470→      conversationId,
471→    });
472→    const errorText = error instanceof Error ? error.message : "workspace conversation failed";
473→    return jsonError(errorText, 500);
474→  }
475→}
